public int minVisibleWhiteTiles(String floor, int numCarpets, int carpetLen) {
    int n = floor.length(), res = n;
    for (int i = 0; i < n - carpetLen + 1; ++i) {
        int count = 0;
        for (int j = 0; j < carpetLen; ++j)
            count += (floor.charAt(i + j) == '1') ? 1 : 0;
        for (int k = 1; k <= numCarpets && k * carpetLen - 1 <= i + carpetLen; ++k) {
            res = Math.min(res, n - count * k);
            if (i + carpetLen < n) {
                count -= (floor.charAt(i + carpetLen - k * carpetLen) == '1') ? 1 : 0;
                count += (floor.charAt(i + carpetLen) == '1') ? 1 : 0;
            }
        }
    }
    return res;
}
